-- Case 005: MERGE with nested source CTE, lateral flatten, deletes, updates, and inserts
MERGE INTO CORE.CUSTOMER_PROFILE AS target USING(WITH ranked_events AS(SELECT e.payload:customer:id::STRING AS customer_id,e.payload:customer:email::STRING AS email,e.payload:customer:name::STRING AS display_name,e.payload:customer:status::STRING AS customer_status,e.payload:customer:locale::STRING AS locale,e.payload:customer:marketing_opt_in::BOOLEAN AS marketing_opt_in,e.event_time,e.event_id,e.payload:customer:addresses AS addresses,ROW_NUMBER() OVER(PARTITION BY e.payload:customer:id::STRING ORDER BY e.event_time DESC,e.loaded_at DESC,e.event_id DESC) AS row_num FROM RAW.CUSTOMER_EVENTS AS e WHERE e.payload:event_type::STRING IN( 'customer.upserted', 'customer.deleted') QUALIFY row_num = 1),address_summary AS(SELECT r.customer_id,COUNT_IF(a.value:type::STRING = 'shipping') AS shipping_address_count,MAX_BY(a.value:country::STRING,a.index) AS last_seen_country,ARRAY_AGG(OBJECT_CONSTRUCT_KEEP_NULL( 'type',a.value:type::STRING, 'country',a.value:country::STRING, 'postal_code',a.value:postal_code::STRING)) WITHIN GROUP(ORDER BY a.index) AS normalized_addresses FROM ranked_events AS r,LATERAL FLATTEN(INPUT => r.addresses,OUTER => TRUE) AS a GROUP BY r.customer_id) SELECT r.customer_id,r.email,r.display_name,r.customer_status,COALESCE(r.locale, 'und') AS locale,COALESCE(r.marketing_opt_in,FALSE) AS marketing_opt_in,COALESCE(a.shipping_address_count,0) AS shipping_address_count,a.last_seen_country,a.normalized_addresses,SHA2_HEX(TO_JSON(OBJECT_CONSTRUCT_KEEP_NULL( 'email',r.email, 'name',r.display_name, 'status',r.customer_status, 'locale',COALESCE(r.locale, 'und'), 'marketing',COALESCE(r.marketing_opt_in,FALSE), 'addresses',a.normalized_addresses)),256) AS row_hash,r.event_time,r.event_id FROM ranked_events AS r LEFT JOIN address_summary AS a ON r.customer_id = a.customer_id) AS source ON target.customer_id = source.customer_id WHEN MATCHED AND source.customer_status = 'deleted' THEN DELETE WHEN MATCHED AND target.row_hash IS DISTINCT FROM source.row_hash THEN UPDATE SET target.email = source.email,target.display_name = source.display_name,target.customer_status = source.customer_status,target.locale = source.locale,target.marketing_opt_in = source.marketing_opt_in,target.shipping_address_count = source.shipping_address_count,target.last_seen_country = source.last_seen_country,target.normalized_addresses = source.normalized_addresses,target.row_hash = source.row_hash,target.source_event_id = source.event_id,target.updated_at = CURRENT_TIMESTAMP() WHEN NOT MATCHED AND source.customer_status <> 'deleted' THEN INSERT(customer_id,email,display_name,customer_status,locale,marketing_opt_in,shipping_address_count,last_seen_country,normalized_addresses,row_hash,source_event_id,created_at,updated_at) VALUES(source.customer_id,source.email,source.display_name,source.customer_status,source.locale,source.marketing_opt_in,source.shipping_address_count,source.last_seen_country,source.normalized_addresses,source.row_hash,source.event_id,CURRENT_TIMESTAMP(),CURRENT_TIMESTAMP());
